<?php require_once "../config/database.php";require_once "../includes/session.php";requireLogin();include "../includes/header.php";$s=$conn->prepare("SELECT rooms.* FROM favorites JOIN rooms ON favorites.room_id=rooms.room_id WHERE favorites.user_id=?");$s->execute([$_SESSION['user_id']]);$rooms=$s->fetchAll(PDO::FETCH_ASSOC);?><div class="container"><h1 class="section-title">Favourites</h1><div class="grid"><?php foreach($rooms as $r):?><div class="card"><img src="<?=e($r['image_url'])?>"><div class="card-body"><h3><?=e($r['room_name'])?></h3><a class="btn gold" href="../room_details.php?id=<?=$r['room_id']?>">View</a></div></div><?php endforeach;?></div></div><?php include "../includes/footer.php";?>
